SELECT TABLE_NAME, COLUMN_NAME, COLUMN_TYPE, EXTRA FROM information_schema.COLUMNS WHERE TABLE_SCHEMA='stridemoor' AND (TABLE_NAME='posts' OR TABLE_NAME='runs' OR TABLE_NAME='routes' OR TABLE_NAME='users') AND (COLUMN_NAME LIKE '%deleted%' OR COLUMN_NAME='review_status' OR COLUMN_NAME='is_hidden' OR COLUMN_NAME='is_banned') ORDER BY TABLE_NAME, ORDINAL_POSITION;
